		Dictionary<string, AtlasSprite> _sprites;

		static Dictionary<string, UIPackage> _packageInstById = new Dictionary<string, UIPackage>();
		static Dictionary<string, UIPackage> _packageInstByName = new Dictionary<string, UIPackage>();
		static List<UIPackage> _packageList = new List<UIPackage>();

		internal static int _constructing;

		[ThreadStatic]
		static int _forceTraceDepth;

		internal static bool ForceTraceActive => _forceTraceDepth > 0;

		private static bool ShouldForceTraceForCreateObject(string pkgName, string resName)
		{
			if (string.IsNullOrWhiteSpace(pkgName) || string.IsNullOrWhiteSpace(resName))
				return false;

			if (!string.Equals(pkgName, "UI", StringComparison.Ordinal))
				return false;

			return string.Equals(resName, "主界面_MainUI", StringComparison.Ordinal)
			       || string.Equals(resName, "主界面刘海屏_MainUI", StringComparison.Ordinal);
		}

		public const string URL_PREFIX = "ui://";

		public UIPackage()
		{
			_items = new List<PackageItem>();
			_itemsById = new Dictionary<string, PackageItem>();
			_itemsByName = new Dictionary<string, PackageItem>();
			_sprites = new Dictionary<string, AtlasSprite>();
		}

		/// <summary>
		/// Return a UIPackage with a certain id.
		/// </summary>
		/// <param name="id">ID of the package.</param>
		/// <returns>UIPackage</returns>
		public static UIPackage GetById(string id)
		{
			UIPackage pkg;
			if (_packageInstById.TryGetValue(id, out pkg))
				return pkg;
			else
				return null;
		}

		/// <summary>
		/// Return a UIPackage with a certain name.
		/// </summary>
		/// <param name="name">Name of the package.</param>
		/// <returns>UIPackage</returns>
		public static UIPackage GetByName(string name)
		{
			bool trace = false;
			Stopwatch sw = null;
			try
			{
				trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
				        && MonoShare.Settings.LogErrors
				        && Environment.OSVersion.Platform != PlatformID.Win32NT;

				if (trace)
				{
					sw = Stopwatch.StartNew();
					MonoShare.CMain.SaveLog($"FairyGUI: [GetByName] TryGetValue 开始 name={name}");
				}
			}
			catch
			{
				trace = false;
			}

			UIPackage pkg;
			if (_packageInstByName.TryGetValue(name, out pkg))
			{
				if (trace)
					MonoShare.CMain.SaveLog($"FairyGUI: [GetByName] TryGetValue 命中（{sw?.ElapsedMilliseconds ?? 0}ms） name={name}");
				return pkg;
			}
			else
			{
				if (trace)
					MonoShare.CMain.SaveLog($"FairyGUI: [GetByName] TryGetValue 未命中（{sw?.ElapsedMilliseconds ?? 0}ms） name={name} keys={_packageInstByName.Count}");
				return null;
			}
		}

		/// <summary>
		/// Add a UI package from a path relative to Unity Resources path.
		/// </summary>
		/// <param name="assetPath">Path relative to resources path.</param>
		/// <returns>UIPackage</returns>
		public static UIPackage AddPackage(string assetPath)
		{
			if (_packageInstById.ContainsKey(assetPath))
				return _packageInstById[assetPath];

			byte[] bytes = null;
			IFairyResourceLoader loader = FairyResourceLoader.Current;
			if (loader != null)
			{
				try
				{
					bytes = loader.ReadPackageBytes(assetPath);
				}
				catch (Exception ex)
				{
					Log.Warning("FairyGUI: load package bytes failed: " + assetPath + ", " + ex.Message);
				}
			}

			if (bytes == null)
				bytes = File.ReadAllBytes(Path.Combine(Stage.game.Content.RootDirectory, assetPath + ".fui"));
			if (bytes == null)
				throw new Exception("FairyGUI: Cannot load ui package in '" + assetPath + "'");

			ByteBuffer buffer = new ByteBuffer(bytes);

			UIPackage pkg = new UIPackage();
			pkg.assetPath = assetPath;
			if (!pkg.LoadPackage(buffer))
				return null;

			_packageInstById[pkg.id] = pkg;
			_packageInstByName[pkg.name] = pkg;
			_packageInstById[assetPath] = pkg;
			_packageList.Add(pkg);
			return pkg;
		}

		/// <summary>
		/// Remove a package. All resources in this package will be disposed.
		/// </summary>
		/// <param name="packageIdOrName"></param>
		/// <param name="allowDestroyingAssets"></param>
		public static void RemovePackage(string packageIdOrName)
		{
			UIPackage pkg = null;
			if (!_packageInstById.TryGetValue(packageIdOrName, out pkg))
			{
				if (!_packageInstByName.TryGetValue(packageIdOrName, out pkg))
					throw new Exception("FairyGUI: '" + packageIdOrName + "' is not a valid package id or name.");
			}
			pkg.Dispose();
			_packageInstById.Remove(pkg.id);
			if (pkg._customId != null)
				_packageInstById.Remove(pkg._customId);
			if (pkg.assetPath != null)
				_packageInstById.Remove(pkg.assetPath);
			_packageInstByName.Remove(pkg.name);
			_packageList.Remove(pkg);
		}

		/// <summary>
		/// 
		/// </summary>
		public static void RemoveAllPackages()
		{
			if (_packageInstById.Count > 0)
			{
				UIPackage[] pkgs = _packageList.ToArray();

				foreach (UIPackage pkg in pkgs)
				{
					pkg.Dispose();
				}
			}
			_packageList.Clear();
			_packageInstById.Clear();
			_packageInstByName.Clear();
		}

		/// <summary>
		/// 
		/// </summary>
		/// <returns></returns>
		public static List<UIPackage> GetPackages()
		{
			return _packageList;
		}

		/// <summary>
		/// Create a UI object.
		/// </summary>
		/// <param name="pkgName">Package name.</param>
		/// <param name="resName">Resource name.</param>
		/// <returns>A UI object.</returns>
		public static GObject CreateObject(string pkgName, string resName)
		{
			bool forceTrace = false;
			try
			{
				forceTrace = ShouldForceTraceForCreateObject(pkgName, resName)
				             && MonoShare.Settings.LogErrors
				             && Environment.OSVersion.Platform != PlatformID.Win32NT;

				if (forceTrace)
					_forceTraceDepth++;
			}
			catch
			{
				forceTrace = false;
			}

			try
			{
				bool trace = false;
			Stopwatch totalSw = null;
			try
			{
				trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
				        && MonoShare.Settings.LogErrors
				        && Environment.OSVersion.Platform != PlatformID.Win32NT;

				if (trace)
				{
					totalSw = Stopwatch.StartNew();
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] static 入口 pkgName={pkgName} resName={resName}");
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] static GetByName 开始 pkgName={pkgName}");
				}
			}
			catch
			{
				trace = false;
			}

			UIPackage pkg = GetByName(pkgName);
			if (trace)
				MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] static GetByName 返回（{totalSw?.ElapsedMilliseconds ?? 0}ms） pkg={(pkg == null ? "null" : pkg.name)}");

			if (pkg != null)
			{
				if (trace)
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] static pkg.CreateObject 开始 pkg={pkg.name} resName={resName}");
				return pkg.CreateObject(resName);
			}
			else
				return null;
			}
			finally
			{
				if (forceTrace)
				{
					try
					{
						_forceTraceDepth--;
					}
					catch
					{
					}
				}
			}
		}

		/// <summary>
		///  Create a UI object.
		/// </summary>
		/// <param name="pkgName">Package name.</param>
		/// <param name="resName">Resource name.</param>
		/// <param name="userClass">Custom implementation of this object.</param>
		/// <returns>A UI object.</returns>
		public static GObject CreateObject(string pkgName, string resName, System.Type userClass)
		{
			UIPackage pkg = GetByName(pkgName);
			if (pkg != null)
				return pkg.CreateObject(resName, userClass);
			else
				return null;
		}

