		/// <summary>
		/// Set a custom id for package, then you can use it in GetById.
		/// </summary>
		public string customId
		{
			get { return _customId; }
			set
			{
				if (_customId != null)
					_packageInstById.Remove(_customId);
				_customId = value;
				if (_customId != null)
					_packageInstById[_customId] = this;
			}
		}

		/// <summary>
		/// 获得本包依赖的包的id列表
		/// </summary>
		public Dictionary<string, string>[] dependencies
		{
			get { return _dependencies; }
		}

		bool LoadPackage(ByteBuffer buffer)
		{
			if (buffer.ReadUint() != 0x46475549)
				throw new Exception("FairyGUI: old package format found in '" + assetPath + "'");

			buffer.version = buffer.ReadInt();
			buffer.ReadBool(); //compressed
			id = buffer.ReadString();
			name = buffer.ReadString();
			if (_packageInstById.ContainsKey(id) && name != _packageInstById[id].name)
			{
				Log.Warning("FairyGUI: Package id conflicts, '" + name + "' and '" + _packageInstById[id].name + "'");
				return false;
			}
			buffer.Skip(20);
			int indexTablePos = buffer.position;
			int cnt;

			buffer.Seek(indexTablePos, 4);

			cnt = buffer.ReadInt();
			string[] stringTable = new string[cnt];
			for (int i = 0; i < cnt; i++)
				stringTable[i] = buffer.ReadString();
			buffer.stringTable = stringTable;

			if (buffer.Seek(indexTablePos, 5))
			{
				cnt = buffer.ReadInt();
				for (int i = 0; i < cnt; i++)
				{
					int index = buffer.ReadUshort();
					int len = buffer.ReadInt();
					stringTable[index] = buffer.ReadString(len);
				}
			}

			buffer.Seek(indexTablePos, 1);

			PackageItem pi;

			cnt = buffer.ReadShort();
			for (int i = 0; i < cnt; i++)
			{
				int nextPos = buffer.ReadInt();
				nextPos += buffer.position;

				pi = new PackageItem();
				pi.owner = this;
				pi.type = (PackageItemType)buffer.ReadByte();
				pi.id = buffer.ReadS();
				pi.name = buffer.ReadS();
				buffer.ReadS(); //path
				pi.file = buffer.ReadS();
				pi.exported = buffer.ReadBool();
				pi.width = buffer.ReadInt();
				pi.height = buffer.ReadInt();

				switch (pi.type)
				{
					case PackageItemType.Image:
						{
							pi.objectType = ObjectType.Image;
							int scaleOption = buffer.ReadByte();
							if (scaleOption == 1)
							{
								Rectangle rect = new Rectangle();
								rect.X = buffer.ReadInt();
								rect.Y = buffer.ReadInt();
								rect.Width = buffer.ReadInt();
								rect.Height = buffer.ReadInt();
								pi.scale9Grid = rect;

								pi.tileGridIndice = buffer.ReadInt();
							}
							else if (scaleOption == 2)
								pi.scaleByTile = true;

							buffer.ReadBool(); //smoothing
							break;
						}

					case PackageItemType.MovieClip:
						{
							buffer.ReadBool(); //smoothing
							pi.objectType = ObjectType.MovieClip;
							pi.rawData = buffer.ReadBuffer();
							break;
						}

					case PackageItemType.Font:
						{
							pi.rawData = buffer.ReadBuffer();
							break;
						}

					case PackageItemType.Component:
						{
							int extension = buffer.ReadByte();
							if (extension > 0)
								pi.objectType = (ObjectType)extension;
							else
								pi.objectType = ObjectType.Component;
							pi.rawData = buffer.ReadBuffer();

							UIObjectFactory.ResolvePackageItemExtension(pi);
							break;
						}

					case PackageItemType.Atlas:
					case PackageItemType.Sound:
					case PackageItemType.Misc:
						{
							pi.file = assetPath + "_" + Path.GetFileNameWithoutExtension(pi.file);
							break;
						}
				}
				_items.Add(pi);
				_itemsById[pi.id] = pi;
				if (pi.name != null)
					_itemsByName[pi.name] = pi;

				buffer.position = nextPos;
			}

			buffer.Seek(indexTablePos, 2);

			cnt = buffer.ReadShort();
			for (int i = 0; i < cnt; i++)
			{
				int nextPos = buffer.ReadShort();
				nextPos += buffer.position;

				string itemId = buffer.ReadS();
				pi = _itemsById[buffer.ReadS()];

				AtlasSprite sprite = new AtlasSprite();
				sprite.atlas = pi;
				sprite.rect.X = buffer.ReadInt();
				sprite.rect.Y = buffer.ReadInt();
				sprite.rect.Width = buffer.ReadInt();
				sprite.rect.Height = buffer.ReadInt();
				sprite.rotated = buffer.ReadBool();
				_sprites[itemId] = sprite;

				buffer.position = nextPos;
			}

			if (buffer.Seek(indexTablePos, 3))
			{
				cnt = buffer.ReadShort();
				for (int i = 0; i < cnt; i++)
				{
					int nextPos = buffer.ReadInt();
					nextPos += buffer.position;

					if (_itemsById.TryGetValue(buffer.ReadS(), out pi))
					{
						if (pi.type == PackageItemType.Image)
						{
							pi.pixelHitTestData = new PixelHitTestData();
							pi.pixelHitTestData.Load(buffer);
						}
					}

					buffer.position = nextPos;
				}
			}

			buffer.Seek(indexTablePos, 0);
			cnt = buffer.ReadShort();
			_dependencies = new Dictionary<string, string>[cnt];
			for (int i = 0; i < cnt; i++)
			{
				Dictionary<string, string> kv = new Dictionary<string, string>();
				kv.Add("id", buffer.ReadS());
				kv.Add("name", buffer.ReadS());
				_dependencies[i] = kv;
			}

			return true;
		}

		/// <summary>
		/// 
		/// </summary>
		public void LoadAllAssets()
		{
			int cnt = _items.Count;
			for (int i = 0; i < cnt; i++)
				GetItemAsset(_items[i]);
		}

		void Dispose()
		{
			int cnt = _items.Count;
			for (int i = 0; i < cnt; i++)
			{
				PackageItem pi = _items[i];
				if (pi.type == PackageItemType.Atlas)
				{
					if (pi.texture != null)
					{
						pi.texture.Dispose();
						pi.texture = null;
					}
				}
				else if (pi.type == PackageItemType.Sound)
				{
					if (pi.audioClip != null)
					{
						pi.audioClip.Dispose();
						pi.audioClip = null;
					}

					if (pi.soundEffect != null)
					{
						pi.soundEffect.Dispose();
						pi.soundEffect = null;
					}
				}
			}
			_items.Clear();
		}

		/// <summary>
		/// 
		/// </summary>
		/// <param name="resName"></param>
		/// <returns></returns>
		public GObject CreateObject(string resName)
		{
			bool trace = false;
			Stopwatch sw = null;
			try
			{
				trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
				        && MonoShare.Settings.LogErrors
				        && Environment.OSVersion.Platform != PlatformID.Win32NT;

				if (trace)
				{
					sw = Stopwatch.StartNew();
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg.CreateObject(string) 入口 pkg={name} resName={resName} itemsByName={_itemsByName?.Count ?? -1}");
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 开始 pkg={name} resName={resName}");
				}
			}
			catch
			{
				trace = false;
			}

			PackageItem pi;
			if (!_itemsByName.TryGetValue(resName, out pi))
			{
				if (trace)
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 未命中（{sw?.ElapsedMilliseconds ?? 0}ms） pkg={name} resName={resName}");
				return null;
			}

			if (trace)
				MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 命中（{sw?.ElapsedMilliseconds ?? 0}ms） pkg={name} resName={resName} itemType={pi?.type}");
			return CreateObject(pi, null);
		}

		/// <summary>
		/// 
		/// </summary>
		/// <param name="resName"></param>
		/// <param name="userClass"></param>
		/// <returns></returns>
		public GObject CreateObject(string resName, System.Type userClass)
		{
			bool trace = false;
			Stopwatch sw = null;
			try
			{
				trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
				        && MonoShare.Settings.LogErrors
				        && Environment.OSVersion.Platform != PlatformID.Win32NT;

				if (trace)
				{
					sw = Stopwatch.StartNew();
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg.CreateObject(type) 入口 pkg={name} resName={resName} userClass={userClass?.FullName} itemsByName={_itemsByName?.Count ?? -1}");
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 开始 pkg={name} resName={resName}");
				}
			}
			catch
			{
				trace = false;
			}

			PackageItem pi;
			if (!_itemsByName.TryGetValue(resName, out pi))
			{
				if (trace)
					MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 未命中（{sw?.ElapsedMilliseconds ?? 0}ms） pkg={name} resName={resName}");
				return null;
			}

			if (trace)
				MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] pkg._itemsByName.TryGetValue 命中（{sw?.ElapsedMilliseconds ?? 0}ms） pkg={name} resName={resName} itemType={pi?.type}");
			return CreateObject(pi, userClass);
		}

		GObject CreateObject(PackageItem item, System.Type userClass)
		{
			Stats.LatestObjectCreation = 0;
			Stats.LatestGraphicsCreation = 0;

            bool trace = false;
            Stopwatch totalSw = null;
            try
            {
                trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
                        && MonoShare.Settings.LogErrors
                        && Environment.OSVersion.Platform != PlatformID.Win32NT;

                if (trace)
                {
                    totalSw = Stopwatch.StartNew();
                    MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] 开始 pkg={name} item={item?.name} type={item?.type}");
                }
            }
            catch
            {
                trace = false;
            }

            if (trace)
            {
                var sw = Stopwatch.StartNew();
                GetItemAsset(item);
                MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] GetItemAsset 完成（{sw.ElapsedMilliseconds}ms） pkg={name} item={item?.name} file={item?.file}");
            }
            else
            {
                GetItemAsset(item);
            }

			GObject g = null;
			if (item.type == PackageItemType.Component)
			{
				if (userClass != null)
					g = (GComponent)Activator.CreateInstance(userClass);
				else
					g = UIObjectFactory.NewObject(item);
			}
			else
				g = UIObjectFactory.NewObject(item);

			if (g == null)
				return null;

            if (trace)
                MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] ConstructFromResource 开始 obj={g.GetType().Name} pkg={name} item={item?.name}");

            _constructing++;
            try
            {
                g.packageItem = item;
                g.ConstructFromResource();
            }
            finally
            {
                _constructing--;
            }

            if (trace)
                MonoShare.CMain.SaveLog($"FairyGUI: [CreateObject] ConstructFromResource 完成（{totalSw?.ElapsedMilliseconds ?? 0}ms） obj={g.GetType().Name} pkg={name} item={item?.name}");
			return g;
		}


		/// <summary>
		/// 
		/// </summary>
		/// <param name="resName"></param>
		/// <returns></returns>
		public object GetItemAsset(string resName)
		{
			PackageItem pi;
			if (!_itemsByName.TryGetValue(resName, out pi))
				return null;

			return GetItemAsset(pi);
		}

		public List<PackageItem> GetItems()
		{
			return _items;
		}

		public PackageItem GetItem(string itemId)
		{
			PackageItem pi;
			if (_itemsById.TryGetValue(itemId, out pi))
				return pi;
			else
				return null;
		}

		public PackageItem GetItemByName(string itemName)
		{
			PackageItem pi;
			if (_itemsByName.TryGetValue(itemName, out pi))
				return pi;
			else
				return null;
		}

		public object GetItemAsset(PackageItem item)
		{
			switch (item.type)
			{
				case PackageItemType.Image:
					if (item.texture == null)
						LoadImage(item);
					return item.texture;

				case PackageItemType.Atlas:
					if (item.texture == null)
						LoadAtlas(item);
					return item.texture;

				case PackageItemType.Sound:
					if (item.audioClip == null)
						LoadSound(item);
					return item.audioClip;

				case PackageItemType.Font:
					if (item.bitmapFont == null)
						LoadFont(item);

					return item.bitmapFont;

				case PackageItemType.MovieClip:
					if (item.frames == null)
						LoadMovieClip(item);

					return item.frames;

				case PackageItemType.Component:
					return item.rawData;

				case PackageItemType.Misc:
					return LoadBinary(item);

				default:
					return null;
			}
		}

		void LoadAtlas(PackageItem item)
		{
            bool trace = false;
            try
            {
                trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
                        && MonoShare.Settings.LogErrors
                        && Environment.OSVersion.Platform != PlatformID.Win32NT;
            }
            catch
            {
                trace = false;
            }

            Stopwatch totalSw = trace ? Stopwatch.StartNew() : null;
            if (trace)
                MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] 开始 pkg={name} file={item?.file}");

			try
			{
				Texture2D tex;
				IFairyResourceLoader loader = FairyResourceLoader.Current;
				if (loader != null)
				{
                    Stopwatch openSw = trace ? Stopwatch.StartNew() : null;
                    if (trace)
                        MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] OpenTextureStream 开始 file={item?.file}");
					using Stream stream = loader.OpenTextureStream(item.file);
                    if (trace && openSw != null)
                        MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] OpenTextureStream 完成（{openSw.ElapsedMilliseconds}ms） file={item?.file}");
#if ANDROID && !REAL_ANDROID
					// 说明：仓库默认 Android 目标在“占位可编译”模式下不强依赖 Mono.Android。
					// Texture2D.FromStream 在 Android 上会引入 Bitmap 相关公开 API，导致缺少 Mono.Android 引用时报错。
					// 真实 Android 构建（REAL_ANDROID）再启用 FromStream 解码。
					tex = new Texture2D(Stage.game.GraphicsDevice, 1, 1);
					tex.SetData(new[] { Microsoft.Xna.Framework.Color.Transparent });
#else
                    Stopwatch decodeSw = trace ? Stopwatch.StartNew() : null;
                    if (trace)
                        MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] Decode 开始 file={item?.file}");
					tex = Texture2D.FromStream(Stage.game.GraphicsDevice, stream);
                    if (trace && decodeSw != null)
                        MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] Decode 完成（{decodeSw.ElapsedMilliseconds}ms） file={item?.file} size={tex?.Width ?? 0}x{tex?.Height ?? 0}");
#endif
				}
				else
				{
					tex = Stage.game.Content.Load<Texture2D>(item.file);
				}
				item.texture = new NTexture(tex, null, tex.Width / item.width, tex.Height / item.height);
                if (trace && totalSw != null)
                    MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] 完成（{totalSw.ElapsedMilliseconds}ms） pkg={name} file={item?.file}");
			}
			catch (Exception ex)
			{
				Log.Warning("FairyGUI: texture '" + item.file + "' not found in " + this.name + ", " + ex.Message);
				item.texture = NTexture.Empty;
                if (trace && totalSw != null)
                    MonoShare.CMain.SaveLog($"FairyGUI: [LoadAtlas] 失败（{totalSw.ElapsedMilliseconds}ms） pkg={name} file={item?.file} err={ex.Message}");
			}
		}

		void LoadImage(PackageItem item)
		{
			AtlasSprite sprite;
			if (_sprites.TryGetValue(item.id, out sprite))
				item.texture = new NTexture((NTexture)GetItemAsset(sprite.atlas), sprite.rect, sprite.rotated);
			else
				item.texture = NTexture.Empty;
		}

		void LoadSound(PackageItem item)
		{
			bool trace = false;
			try
			{
				trace = (ForceTraceActive || MonoShare.FairyGuiHost.MobileMainHudCreateTraceActive)
				        && MonoShare.Settings.LogErrors
				        && Environment.OSVersion.Platform != PlatformID.Win32NT;
			}
			catch
			{
				trace = false;
			}

			Stopwatch totalSw = trace ? Stopwatch.StartNew() : null;
			if (trace)
				MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] 开始 pkg={name} file={item?.file}");

			try
			{
				SoundEffect audioFile;
				IFairyResourceLoader loader = FairyResourceLoader.Current;
				if (loader != null)
				{
					Stopwatch openSw = trace ? Stopwatch.StartNew() : null;
					if (trace)
						MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] OpenSoundStream 开始 file={item?.file}");
					using Stream stream = loader.OpenSoundStream(item.file);
					if (trace && openSw != null)
						MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] OpenSoundStream 完成（{openSw.ElapsedMilliseconds}ms） file={item?.file}");

					Stopwatch decodeSw = trace ? Stopwatch.StartNew() : null;
					if (trace)
						MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] Decode 开始 file={item?.file}");
					audioFile = SoundEffect.FromStream(stream);
					if (trace && decodeSw != null)
						MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] Decode 完成（{decodeSw.ElapsedMilliseconds}ms） file={item?.file}");
					item.soundEffect = audioFile;
				}
				else
				{
					audioFile = Stage.game.Content.Load<SoundEffect>(item.file);
				}

				item.audioClip = audioFile?.CreateInstance();
				if (trace && totalSw != null)
					MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] 完成（{totalSw.ElapsedMilliseconds}ms） pkg={name} file={item?.file}");
			}
			catch (Exception ex)
			{
				Log.Warning("FairyGUI: sound '" + item.file + "' not found in " + this.name + ", " + ex.Message);
				item.audioClip = null;
				if (trace && totalSw != null)
					MonoShare.CMain.SaveLog($"FairyGUI: [LoadSound] 失败（{totalSw.ElapsedMilliseconds}ms） pkg={name} file={item?.file} err={ex.Message}");
			}
		}

		byte[] LoadBinary(PackageItem item)
		{
			try
			{
				IFairyResourceLoader loader = FairyResourceLoader.Current;
				if (loader != null)
				{
					using Stream stream = loader.OpenBinaryStream(item.file);
					using var ms = new MemoryStream();
					stream.CopyTo(ms);
					return ms.ToArray();
				}

				return File.ReadAllBytes(item.file);
			}
			catch (Exception ex)
			{
				Log.Warning("FairyGUI: binary '" + item.file + "' not found in " + this.name + ", " + ex.Message);
				return null;
			}
		}

		void LoadMovieClip(PackageItem item)
		{
			ByteBuffer buffer = item.rawData;

			buffer.Seek(0, 0);

			item.interval = buffer.ReadInt() / 1000f;
			item.swing = buffer.ReadBool();
			item.repeatDelay = buffer.ReadInt() / 1000f;

			buffer.Seek(0, 1);

			int frameCount = buffer.ReadShort();
			item.frames = new MovieClip.Frame[frameCount];

			string spriteId;
			MovieClip.Frame frame;
			AtlasSprite sprite;

			for (int i = 0; i < frameCount; i++)
			{
				int nextPos = buffer.ReadShort();
				nextPos += buffer.position;

				frame = new MovieClip.Frame();
				float fx = buffer.ReadInt();
				float fy = buffer.ReadInt();
				buffer.ReadInt(); //width
				buffer.ReadInt(); //height
				frame.addDelay = buffer.ReadInt() / 1000f;
				spriteId = buffer.ReadS();

				if (spriteId != null && _sprites.TryGetValue(spriteId, out sprite))
				{
					frame.texture = new NTexture((NTexture)GetItemAsset(sprite.atlas), sprite.rect, sprite.rotated,
						new Vector2(item.width, item.height), new Vector2(fx, fy));
				}
				item.frames[i] = frame;

				buffer.position = nextPos;
			}
		}

		void LoadFont(PackageItem item)
		{
			BitmapFont font = new BitmapFont(item);
			item.bitmapFont = font;
			ByteBuffer buffer = item.rawData;

			buffer.Seek(0, 0);

			bool ttf = buffer.ReadBool();
			font.colorEnabled = buffer.ReadBool();
			font.scaleEnabled = buffer.ReadBool();
			buffer.ReadBool();//hasChannel
			int fontSize = buffer.ReadInt();
			int xadvance = buffer.ReadInt();
			int lineHeight = buffer.ReadInt();

			float texScaleX = 1;
			float texScaleY = 1;
			NTexture mainTexture = null;
			AtlasSprite mainSprite = null;
			if (ttf && _sprites.TryGetValue(item.id, out mainSprite))
			{
				mainTexture = (NTexture)GetItemAsset(mainSprite.atlas);
				texScaleX = mainTexture.root.uvRect.Width / mainTexture.width;
				texScaleY = mainTexture.root.uvRect.Height / mainTexture.height;
			}

			buffer.Seek(0, 1);

			BitmapFont.BMGlyph bg;
			int cnt = buffer.ReadInt();
			for (int i = 0; i < cnt; i++)
			{
				int nextPos = buffer.ReadShort();
				nextPos += buffer.position;

				bg = new BitmapFont.BMGlyph();
				char ch = buffer.ReadChar();
				font.AddChar(ch, bg);

				string img = buffer.ReadS();
				int bx = buffer.ReadInt();
				int by = buffer.ReadInt();
				bg.offsetX = buffer.ReadInt();
				bg.offsetY = buffer.ReadInt();
				bg.width = buffer.ReadInt();
				bg.height = buffer.ReadInt();
				bg.advance = buffer.ReadInt();
				bg.channel = buffer.ReadByte();
				if (bg.channel == 1)
					bg.channel = 3;
				else if (bg.channel == 2)
					bg.channel = 2;
				else if (bg.channel == 3)
					bg.channel = 1;

				if (ttf)
				{
					if (mainSprite.rotated)
					{
						bg.uv[0] = new Vector2((float)(by + bg.height + mainSprite.rect.X) * texScaleX,
							1 - (float)(mainSprite.rect.Bottom - bx) * texScaleY);
						bg.uv[1] = new Vector2(bg.uv[0].X - (float)bg.height * texScaleX, bg.uv[0].Y);
						bg.uv[2] = new Vector2(bg.uv[1].X, bg.uv[0].Y + (float)bg.width * texScaleY);
						bg.uv[3] = new Vector2(bg.uv[0].X, bg.uv[2].Y);
					}
					else
					{
						bg.uv[0] = new Vector2((float)(bx + mainSprite.rect.X) * texScaleX,
							1 - (float)(by + bg.height + mainSprite.rect.Y) * texScaleY);
						bg.uv[1] = new Vector2(bg.uv[0].X, bg.uv[0].Y + (float)bg.height * texScaleY);
						bg.uv[2] = new Vector2(bg.uv[0].X + (float)bg.width * texScaleX, bg.uv[1].Y);
						bg.uv[3] = new Vector2(bg.uv[2].X, bg.uv[0].Y);
					}

					bg.lineHeight = lineHeight;
				}
				else
				{
					PackageItem charImg;
					if (_itemsById.TryGetValue(img, out charImg))
					{
						GetItemAsset(charImg);
						charImg.texture.GetUV(bg.uv);
						bg.width = charImg.texture.width;
						bg.height = charImg.texture.height;

						if (mainTexture == null)
							mainTexture = charImg.texture.root;
					}

					if (fontSize == 0)
						fontSize = bg.height;

					if (bg.advance == 0)
					{
						if (xadvance == 0)
							bg.advance = bg.offsetX + bg.width;
						else
							bg.advance = xadvance;
					}

					bg.lineHeight = bg.offsetY < 0 ? bg.height : (bg.offsetY + bg.height);
					if (bg.lineHeight < font.size)
						bg.lineHeight = font.size;
				}

				buffer.position = nextPos;
			}

			font.size = fontSize;
			font.mainTexture = mainTexture;
		}
	}
}
